sys_script_email.script:
(function runMailScript( /* GlideRecord */ current, /* TemplatePrinter */ template,
    /* Optional EmailOutbound */
    email, /* Optional GlideRecord */ email_action,
    /* Optional GlideRecord */
    event) {
    var eventName = event.getValue("name");
    var comments = null;
    if (eventName === Constants.EVENT.requestRejected) {
        var documentId = current.getValue("sys_id");
        var approvalGr = new GlideRecord("sysapproval_approver");
        approvalGr.addQuery("document_id", documentId);
        approvalGr.addQuery("state", "rejected");
        approvalGr.query();

        if (approvalGr.next()) {
            comments = approvalGr.getDisplayValue("comments");
        }
    } else {
        comments = current.getDisplayValue("comments");
    }

    var value = comments.split("(Comments)")[1].trim();
    template.print('<pre style="font-family: \'Roboto\', sans-serif; font-size: 14px; font-weight: 400; color: #333333; margin: 0; margin-bottom: 5px; word-break: break-all;">' + value + '</pre>');

})(current, template, email, email_action, event);
